@@ -0,0 +1,624 @@
+//! narcolepsyd — idle power optimizer for Linux laptops with Intel hybrid CPUs
+//!
+//! Automatically detects Intel hybrid CPU topology (P-cores, E-cores, LP E-cores)
+//! and aggressively parks high-power cores when the user is idle. Display stays on.
+//! All changes are reverted instantly on keyboard/touchpad input.
+//!
+//! Techniques applied during idle:
+//!   - Offline P-cores and most E-cores
+//!   - Set EPP (Energy Performance Preference) to maximum power saving
+//!   - Disable turbo boost
+//!   - Cap remaining core frequencies
+//!   - Suspend non-essential USB devices (webcam, fingerprint reader)
+//!
+//! Works on any Intel hybrid CPU: Alder Lake, Raptor Lake, Meteor Lake,
+//! Lunar Lake, Arrow Lake, and newer.
+
+use std::collections::HashMap;
+use std::fs;
+use std::os::unix::io::RawFd;
+use std::sync::atomic::{AtomicBool, Ordering};
+use std::time::{Duration, Instant};
+
+use log::{debug, error, info, warn};
+
+// ----- configuration -----
+
+const IDLE_TIMEOUT: Duration = Duration::from_secs(3);
+const POLL_TIMEOUT_MS: i32 = 3000;
+const POLL_TIMEOUT_LP_MS: i32 = 5000;
+const LOW_POWER_FREQ_KHZ: &str = "800000";
+const KEEP_E_CORES: usize = 2; // how many E-cores to keep online in low-power
+
+const INHIBIT_NAMES: &[&str] = &[
+    "zoom", "ffmpeg", "obs", "vlc", "mpv", "totem", "rsync", "scp",
+];
+
+static RUNNING: AtomicBool = AtomicBool::new(true);
+
+// ----- sysfs helpers -----
+
+fn write_sysfs(path: &str, value: &str) -> bool {
+    fs::write(path, value).is_ok()
+}
+
+fn read_sysfs(path: &str) -> Option<String> {
+    fs::read_to_string(path).ok().map(|s| s.trim().to_string())
+}
+
+// ----- CPU topology detection -----
+
+#[derive(Debug, Clone, Copy, PartialEq, Eq)]
+enum CoreType {
+    PCore,
+    ECore,
+    LPECore,
+    Unknown,
+}
+
+#[derive(Debug)]
+struct CpuInfo {
+    id: u32,
+    core_type: CoreType,
+    max_freq_khz: u64,
+    can_offline: bool,
+}
+
+#[derive(Debug)]
+struct Topology {
+    cpus: Vec<CpuInfo>,
+    /// CPUs to offline during low-power (P-cores + extra E-cores)
+    park_list: Vec<u32>,
+    /// CPUs to keep online and frequency-cap during low-power
+    cap_list: Vec<u32>,
+    /// All CPU IDs
+    all_cpus: Vec<u32>,
+}
+
+fn detect_topology() -> Topology {
+    let num_cpus = num_online_cpus();
+    let mut cpus = Vec::new();
+
+    // Gather per-CPU info
+    for id in 0..num_cpus {
+        let max_freq = read_sysfs(&format!(
+            "/sys/devices/system/cpu/cpu{id}/cpufreq/cpuinfo_max_freq"
+        ))
+        .and_then(|s| s.parse::<u64>().ok())
+        .unwrap_or(0);
+
+        // CPU 0 can never be offlined
+        let can_offline = id > 0;
+
+        cpus.push(CpuInfo {
+            id,
+            core_type: CoreType::Unknown,
+            max_freq_khz: max_freq,
+            can_offline,
+        });
+    }
+
+    if cpus.is_empty() {
+        return Topology {
+            cpus: vec![],
+            park_list: vec![],
+            cap_list: vec![],
+            all_cpus: vec![],
+        };
+    }
+
+    // Classify by max frequency
+    // P-cores have the highest max freq, LP E-cores the lowest, E-cores in between
+    let max_freq = cpus.iter().map(|c| c.max_freq_khz).max().unwrap_or(0);
+    let min_freq = cpus.iter().map(|c| c.max_freq_khz).min().unwrap_or(0);
+
+    // Check if there are 3+ distinct frequency tiers (P, E, LP-E)
+    let has_mid_tier = cpus
+        .iter()
+        .any(|c| c.max_freq_khz != max_freq && c.max_freq_khz != min_freq && c.max_freq_khz != 0);
+
+    for cpu in &mut cpus {
+        if cpu.max_freq_khz == 0 {
+            cpu.core_type = CoreType::Unknown;
+        } else if cpu.max_freq_khz == max_freq && max_freq != min_freq {
+            cpu.core_type = CoreType::PCore;
+        } else if cpu.max_freq_khz == min_freq && min_freq != max_freq {
+            if has_mid_tier {
+                cpu.core_type = CoreType::LPECore;
+            } else {
+                cpu.core_type = CoreType::ECore;
+            }
+        } else if cpu.max_freq_khz == max_freq && max_freq == min_freq {
+            // All cores same freq — not a hybrid CPU
+            cpu.core_type = CoreType::ECore;
+        } else {
+            cpu.core_type = CoreType::ECore;
+        }
+    }
+
+    let p_cores: Vec<u32> = cpus
+        .iter()
+        .filter(|c| c.core_type == CoreType::PCore && c.can_offline)
+        .map(|c| c.id)
+        .collect();
+    let e_cores: Vec<u32> = cpus
+        .iter()
+        .filter(|c| c.core_type == CoreType::ECore)
+        .map(|c| c.id)
+        .collect();
+    let lp_cores: Vec<u32> = cpus
+        .iter()
+        .filter(|c| c.core_type == CoreType::LPECore)
+        .map(|c| c.id)
+        .collect();
+
+    // Build park and cap lists
+    let mut park_list = Vec::new();
+    let mut cap_list = Vec::new();
+
+    // Park all P-cores (except CPU 0 which can't be offlined)
+    park_list.extend_from_slice(&p_cores);
+
+    // Keep KEEP_E_CORES E-cores online, park the rest
+    for (i, &cpu) in e_cores.iter().enumerate() {
+        if i < KEEP_E_CORES {
+            cap_list.push(cpu);
+        } else if cpus[cpu as usize].can_offline {
+            park_list.push(cpu);
+        }
+    }
+
+    // LP E-cores always stay online (they're already low power)
+    // but we cap their frequency too
+    cap_list.extend_from_slice(&lp_cores);
+
+    let all_cpus: Vec<u32> = cpus.iter().map(|c| c.id).collect();
+
+    info!(
+        "Detected topology: {} P-cores, {} E-cores, {} LP-E-cores ({} total)",
+        p_cores.len(),
+        e_cores.len(),
+        lp_cores.len(),
+        cpus.len()
+    );
+    info!(
+        "Will park {} cores, keep {} cores on low-power",
+        park_list.len(),
+        cap_list.len() + 1 // +1 for CPU0
+    );
+
+    Topology {
+        cpus,
+        park_list,
+        cap_list,
+        all_cpus,
+    }
+}
+
+fn num_online_cpus() -> u32 {
+    // Read from /sys/devices/system/cpu/present (e.g. "0-13")
+    read_sysfs("/sys/devices/system/cpu/present")
+        .and_then(|s| {
+            let parts: Vec<&str> = s.split('-').collect();
+            if parts.len() == 2 {
+                parts[1].parse::<u32>().ok().map(|n| n + 1)
+            } else {
+                Some(1)
+            }
+        })
+        .unwrap_or(1)
+}
+
+// ----- input device monitoring -----
+
+struct InputDevice {
+    #[allow(dead_code)]
+    path: String,
+    #[allow(dead_code)]
+    name: String,
+    fd: RawFd,
+}
+
+impl Drop for InputDevice {
+    fn drop(&mut self) {
+        unsafe {
+            libc::close(self.fd);
+        }
+    }
+}
+
+fn open_input_devices() -> Vec<InputDevice> {
+    let mut devices = Vec::new();
+    let input_dir = std::path::Path::new("/dev/input");
+
+    let mut entries: Vec<_> = match fs::read_dir(input_dir) {
+        Ok(e) => e.filter_map(|e| e.ok()).collect(),
+        Err(_) => return devices,
+    };
+    entries.sort_by_key(|e| e.file_name());
+
+    for entry in entries {
+        let fname = entry.file_name().to_string_lossy().to_string();
+        if !fname.starts_with("event") {
+            continue;
+        }
+
+        let path = entry.path().to_string_lossy().to_string();
+        let c_path = match std::ffi::CString::new(path.as_bytes()) {
+            Ok(p) => p,
+            Err(_) => continue,
+        };
+        let fd = unsafe { libc::open(c_path.as_ptr(), libc::O_RDONLY | libc::O_NONBLOCK) };
+        if fd < 0 {
+            continue;
+        }
+
+        // EVIOCGNAME(256)
+        let mut name_buf = [0u8; 256];
+        let ret = unsafe {
+            libc::ioctl(fd, 0x80FF4506u32 as libc::c_ulong, name_buf.as_mut_ptr())
+        };
+        if ret < 0 {
+            unsafe { libc::close(fd); }
+            continue;
+        }
+        let name_end = name_buf.iter().position(|&b| b == 0).unwrap_or(256);
+        let name = String::from_utf8_lossy(&name_buf[..name_end]).to_lowercase();
+
+        // EVIOCGBIT(0, 32)
+        let mut cap_buf = [0u8; 32];
+        let ret = unsafe {
+            libc::ioctl(fd, 0x80204520u32 as libc::c_ulong, cap_buf.as_mut_ptr())
+        };
+        if ret < 0 {
+            unsafe { libc::close(fd); }
+            continue;
+        }
+
+        let has_key = cap_buf[0] & (1 << 1) != 0;
+        let has_rel = cap_buf[0] & (1 << 2) != 0;
+        let has_abs = cap_buf[0] & (1 << 3) != 0;
+
+        let is_user_input =
+            if has_key && (name.contains("keyboard") || name.contains("kbd")) {
+                true
+            } else if has_rel || has_abs {
+                ["mouse", "touch", "track", "pad", "pointer", "synaptics", "elan", "finger"]
+                    .iter()
+                    .any(|w| name.contains(w))
+            } else if has_key {
+                !["video", "button", "power", "lid", "sleep", "rfkill"]
+                    .iter()
+                    .any(|w| name.contains(w))
+            } else {
+                false
+            };
+
+        if is_user_input {
+            info!("Monitoring input: {} ({})", path, name);
+            devices.push(InputDevice { path, name, fd });
+        } else {
+            unsafe { libc::close(fd); }
+        }
+    }
+    devices
+}
+
+fn drain_fd(fd: RawFd) {
+    let mut buf = [0u8; 4096];
+    loop {
+        let n = unsafe { libc::read(fd, buf.as_mut_ptr() as *mut libc::c_void, buf.len()) };
+        if n <= 0 {
+            break;
+        }
+    }
+}
+
+fn poll_inputs(devices: &[InputDevice], timeout_ms: i32) -> bool {
+    let mut pollfds: Vec<libc::pollfd> = devices
+        .iter()
+        .map(|d| libc::pollfd {
+            fd: d.fd,
+            events: libc::POLLIN,
+            revents: 0,
+        })
+        .collect();
+
+    let ret =
+        unsafe { libc::poll(pollfds.as_mut_ptr(), pollfds.len() as libc::nfds_t, timeout_ms) };
+
+    if ret > 0 {
+        for pfd in &pollfds {
+            if pfd.revents & libc::POLLIN != 0 {
+                drain_fd(pfd.fd);
+            }
+        }
+        true
+    } else {
+        false
+    }
+}
+
+// ----- power state management -----
+
+struct SavedState {
+    epp: HashMap<u32, String>,
+    max_freq: HashMap<u32, String>,
+    cpu_online: HashMap<u32, String>,
+    turbo: Option<String>,
+    usb_controls: Vec<(String, String)>,
+}
+
+impl SavedState {
+    fn new() -> Self {
+        Self {
+            epp: HashMap::new(),
+            max_freq: HashMap::new(),
+            cpu_online: HashMap::new(),
+            turbo: None,
+            usb_controls: Vec::new(),
+        }
+    }
+}
+
+fn enter_low_power(state: &mut SavedState, topo: &Topology) {
+    debug!("Entering low-power mode");
+
+    // 1. Set EPP to power on all cores
+    for &cpu in &topo.all_cpus {
+        let path = format!(
+            "/sys/devices/system/cpu/cpu{cpu}/cpufreq/energy_performance_preference"
+        );
+        if let Some(current) = read_sysfs(&path) {
+            state.epp.insert(cpu, current);
+            write_sysfs(&path, "power");
+        }
+    }
+
+    // 2. Disable turbo
+    let turbo_path = "/sys/devices/system/cpu/intel_pstate/no_turbo";
+    state.turbo = read_sysfs(turbo_path);
+    write_sysfs(turbo_path, "1");
+
+    // 3. Cap kept cores
+    for &cpu in &topo.cap_list {
+        let path = format!("/sys/devices/system/cpu/cpu{cpu}/cpufreq/scaling_max_freq");
+        if let Some(current) = read_sysfs(&path) {
+            state.max_freq.insert(cpu, current);
+            write_sysfs(&path, LOW_POWER_FREQ_KHZ);
+        }
+    }
+
+    // 4. Offline parked cores
+    for &cpu in &topo.park_list {
+        let path = format!("/sys/devices/system/cpu/cpu{cpu}/online");
+        if let Some(current) = read_sysfs(&path) {
+            state.cpu_online.insert(cpu, current);
+            write_sysfs(&path, "0");
+        }
+    }
+
+    // 5. Suspend non-essential USB
+    suspend_usb(state);
+}
+
+fn exit_low_power(state: &mut SavedState) {
+    debug!("Restoring normal power");
+
+    let mut cpus: Vec<u32> = state.cpu_online.keys().copied().collect();
+    cpus.sort();
+    for cpu in cpus {
+        write_sysfs(&format!("/sys/devices/system/cpu/cpu{cpu}/online"), "1");
+    }
+    state.cpu_online.clear();
+
+    for (cpu, freq) in state.max_freq.drain() {
+        write_sysfs(
+            &format!("/sys/devices/system/cpu/cpu{cpu}/cpufreq/scaling_max_freq"),
+            &freq,
+        );
+    }
+
+    for (cpu, epp) in state.epp.drain() {
+        write_sysfs(
+            &format!("/sys/devices/system/cpu/cpu{cpu}/cpufreq/energy_performance_preference"),
+            &epp,
+        );
+    }
+
+    if let Some(ref t) = state.turbo.take() {
+        write_sysfs("/sys/devices/system/cpu/intel_pstate/no_turbo", t);
+    }
+
+    resume_usb(state);
+}
+
+fn suspend_usb(state: &mut SavedState) {
+    let usb_dir = std::path::Path::new("/sys/bus/usb/devices");
+    let entries = match fs::read_dir(usb_dir) {
+        Ok(e) => e,
+        Err(_) => return,
+    };
+
+    for entry in entries.filter_map(|e| e.ok()) {
+        let dev = entry.path();
+        let product = dev.join("product");
+        let control = dev.join("power/control");
+        if !product.exists() || !control.exists() {
+            continue;
+        }
+
+        let pname = read_sysfs(product.to_str().unwrap_or(""))
+            .unwrap_or_default()
+            .to_lowercase();
+
+        if ["camera", "webcam", "fingerprint", "biometric"]
+            .iter()
+            .any(|w| pname.contains(w))
+        {
+            let ctrl = control.to_string_lossy().to_string();
+            if let Some(cur) = read_sysfs(&ctrl) {
+                if cur == "on" {
+                    write_sysfs(&ctrl, "auto");
+                    state.usb_controls.push((ctrl, cur));
+                    debug!("Suspended USB: {}", pname);
+                }
+            }
+        }
+    }
+}
+
+fn resume_usb(state: &mut SavedState) {
+    for (path, orig) in state.usb_controls.drain(..) {
+        write_sysfs(&path, &orig);
+    }
+}
+
+// ----- checks -----
+
+fn is_on_battery() -> bool {
+    // Check common AC power supply paths
+    for name in &["AC", "AC0", "ADP0", "ADP1", "ACAD"] {
+        let path = format!("/sys/class/power_supply/{name}/online");
+        if let Some(val) = read_sysfs(&path) {
+            return val == "0";
+        }
+    }
+    // If no AC supply found, check if any supply is of type "Mains"
+    if let Ok(entries) = fs::read_dir("/sys/class/power_supply") {
+        for entry in entries.filter_map(|e| e.ok()) {
+            let type_path = entry.path().join("type");
+            if read_sysfs(type_path.to_str().unwrap_or("")) == Some("Mains".into()) {
+                let online_path = entry.path().join("online");
+                if let Some(val) = read_sysfs(online_path.to_str().unwrap_or("")) {
+                    return val == "0";
+                }
+            }
+        }
+    }
+    true // assume battery if we can't tell
+}
+
+fn is_inhibited() -> bool {
+    let out = std::process::Command::new("ps")
+        .args(["-eo", "comm="])
+        .output();
+    match out {
+        Ok(o) => {
+            let text = String::from_utf8_lossy(&o.stdout);
+            text.lines()
+                .any(|line| INHIBIT_NAMES.iter().any(|&n| line.trim() == n))
+        }
+        Err(_) => false,
+    }
+}
+
+fn is_hybrid_cpu() -> bool {
+    // Check for intel_pstate driver (Intel hybrid CPUs)
+    std::path::Path::new("/sys/devices/system/cpu/intel_pstate").exists()
+}
+
+// ----- signals -----
+
+extern "C" fn on_signal(_: libc::c_int) {
+    RUNNING.store(false, Ordering::SeqCst);
+}
+
+fn install_signals() {
+    unsafe {
+        libc::signal(libc::SIGTERM, on_signal as *const () as libc::sighandler_t);
+        libc::signal(libc::SIGINT, on_signal as *const () as libc::sighandler_t);
+    }
+}
+
+// ----- main -----
+
+fn main() {
+    env_logger::Builder::from_env(env_logger::Env::default().default_filter_or("info"))
+        .format_timestamp_secs()
+        .init();
+
+    if unsafe { libc::geteuid() } != 0 {
+        eprintln!("narcolepsyd must run as root");
+        std::process::exit(1);
+    }
+
+    install_signals();
+
+    if !is_hybrid_cpu() {
+        warn!("No Intel hybrid CPU detected (intel_pstate not found)");
+        warn!("narcolepsyd is designed for Intel hybrid CPUs (Alder Lake and newer)");
+        std::process::exit(1);
+    }
+
+    let topo = detect_topology();
+    if topo.park_list.is_empty() {
+        warn!("No cores to park — nothing to do");
+        std::process::exit(0);
+    }
+
+    let devices = open_input_devices();
+    if devices.is_empty() {
+        error!("No input devices found — run as root");
+        std::process::exit(1);
+    }
+
+    info!(
+        "narcolepsyd started: {} input devices, {} cores to park on idle",
+        devices.len(),
+        topo.park_list.len()
+    );
+
+    let mut state = SavedState::new();
+    let mut in_lp = false;
+    let t0 = Instant::now();
+    let mut total_lp: f64 = 0.0;
+    let mut entries: u64 = 0;
+    let mut idle_since = Instant::now();
+
+    while RUNNING.load(Ordering::Relaxed) {
+        if !in_lp {
+            let activity = poll_inputs(&devices, POLL_TIMEOUT_MS);
+            if activity {
+                idle_since = Instant::now();
+                continue;
+            }
+            if idle_since.elapsed() < IDLE_TIMEOUT {
+                continue;
+            }
+            if !is_on_battery() || is_inhibited() {
+                idle_since = Instant::now();
+                continue;
+            }
+            enter_low_power(&mut state, &topo);
+            in_lp = true;
+            entries += 1;
+            idle_since = Instant::now();
+        } else {
+            let activity = poll_inputs(&devices, POLL_TIMEOUT_LP_MS);
+            if activity || !is_on_battery() || is_inhibited() {
+                total_lp += idle_since.elapsed().as_secs_f64();
+                exit_low_power(&mut state);
+                in_lp = false;
+                idle_since = Instant::now();
+            }
+        }
+    }
+
+    if in_lp {
+        total_lp += idle_since.elapsed().as_secs_f64();
+        exit_low_power(&mut state);
+    }
+
+    let uptime = t0.elapsed().as_secs_f64();
+    let pct = if uptime > 0.0 {
+        total_lp / uptime * 100.0
+    } else {
+        0.0
+    };
+    info!(
+        "Stats: {} low-power entries, {:.0}s low-power / {:.0}s uptime ({:.0}%)",
+        entries, total_lp, uptime, pct
+    );
+    info!("narcolepsyd stopped");
+}
